def main():
    with open(IN_PATH, newline="", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        fieldnames = reader.fieldnames
        rows = list(reader)

    assert fieldnames is not None
    missing = []
    for r in rows:
        pid = r["placement_id"]
        if pid not in ROWS:
            missing.append(pid)
            continue
        trad, evol, dev, refs = ROWS[pid]
        r["traditional_meaning_ar"] = trad
        r["evolutionary_meaning_ar"] = evol
        r["developmental_task_ar"] = dev
        r["key_references"] = refs
        r["status"] = "filled"

    if missing:
        raise SystemExit(f"Missing content for: {missing}")

    os.makedirs(os.path.dirname(OUT_PATH), exist_ok=True)
    with open(OUT_PATH, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        for r in rows:
            writer.writerow(r)

    # Verify
    with open(OUT_PATH, newline="", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        out_rows = list(reader)
    print(f"Wrote {len(out_rows)} rows to {OUT_PATH}")

    # Word count sanity check
    for r in out_rows:
        wc = (
            len(r["traditional_meaning_ar"].split())
            + len(r["evolutionary_meaning_ar"].split())
            + len(r["developmental_task_ar"].split())
        )
        # warn out of range
        if wc < 200 or wc > 350:
            print(f"  WARN {r['placement_id']}: total word count {wc}")
        # Forbidden checks
        forbidden = ["Chiron", "North Node", "South Node", "—", "المسيح", "Steiner", "Anthroposophy"]
        for tok in forbidden:
            for col in ["traditional_meaning_ar", "evolutionary_meaning_ar", "developmental_task_ar"]:
                if tok in r[col]:
                    print(f"  FORBIDDEN '{tok}' in {r['placement_id']}/{col}")


if __name__ == "__main__":
    main()
